gsap.registerPlugin(ScrollTrigger);

// ---- Physics constants ----
// ---- Config via data-attributes en .soga-sticky-wrapper ----
// data-gravity       → peso/caída (default 0.003)
// data-damping       → amortiguación (default 0.985, rango 0.97-0.999)
// data-mouse-force   → fuerza del mouse/grab (default 0.12)
// data-tube-radius   → grosor de la soga (default 0.055)
// data-rope-position → posición horizontal % (default 72, rango 50-90)
// data-scroll-dist   → px de scroll para recorrer la soga (default 3200)
// data-segments      → partículas de física (default 100, rango 60-160)
// data-smooth        → subdivisiones visuales entre partículas (default 3, rango 1-5)
// data-tube-sides    → lados del tubo circular (default 16, rango 8-24)
// data-iterations    → iteraciones de constraints (default 60; más = menos elástica, más soga real; rango 20-80)
const _w = document.querySelector('.soga-sticky-wrapper');
const cfg = {
  gravity:      parseFloat(_w?.dataset?.gravity)      || 0.005,
  damping:      parseFloat(_w?.dataset?.damping)      || 0.88,
  mouseForce:   parseFloat(_w?.dataset?.mouseForce)   || 0.12,
  tubeRadius:   parseFloat(_w?.dataset?.tubeRadius)   || 0.055,
  ropePosition: parseFloat(_w?.dataset?.ropePosition) || 72,
  scrollDist:   parseFloat(_w?.dataset?.scrollDist)   || 3200,
  segments:     parseInt(_w?.dataset?.segments, 10)    || 100,
  smooth:       parseInt(_w?.dataset?.smooth, 10)      || 3,
  tubeSides:    parseInt(_w?.dataset?.tubeSides, 10)   || 16,
  iterations:   parseInt(_w?.dataset?.iterations, 10)  || 80,
};

const NUM_SEGMENTS = Math.max(40, Math.min(200, cfg.segments));
const GRAVITY      = cfg.gravity;
const DAMPING      = cfg.damping;
const ITERATIONS   = Math.max(10, Math.min(80, cfg.iterations));
const TUBE_SEGS    = Math.max(8, Math.min(32, cfg.tubeSides));
const TUBE_R       = cfg.tubeRadius;
const RENDER_SUBDIV = Math.max(1, Math.min(6, cfg.smooth));
const N            = NUM_SEGMENTS + 1;
const RENDER_N     = NUM_SEGMENTS * RENDER_SUBDIV + 1;

// ---- THREE.js ----
let W = window.innerWidth;
let H = window.innerHeight;

const renderer = new THREE.WebGLRenderer({
  canvas: document.querySelector('.soga-canvas'),
  antialias: true,
  alpha: true       // transparent so #f9f9fa background shows
});
renderer.setSize(W, H);
renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
renderer.setClearColor(0x000000, 0);

const scene  = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(50, W / H, 0.1, 1000);
camera.position.z = 6;

const fov      = 50 * Math.PI / 180;
const mouse2D  = { x: -9999, y: -9999 };
const mouse3D  = new THREE.Vector3(-9999, 0, 0);

function screenToWorld(ex, ey) {
  const nx   = (ex / W) * 2 - 1;
  const ny   = -(ey / H) * 2 + 1;
  const halfH = Math.tan(fov / 2) * camera.position.z;
  const halfW = halfH * (W / H);
  return { x: nx * halfW, y: ny * halfH };
}

// ---- Grab / drag interaction ----
function isStickyActive() {
  const rect = document.querySelector('.soga-sticky-wrapper').getBoundingClientRect();
  return rect.top <= 1 && rect.bottom >= H - 1;
}

window.addEventListener('mousemove', (e) => {
  mouse2D.x = e.clientX; mouse2D.y = e.clientY;
  const w = screenToWorld(e.clientX, e.clientY);
  mouse3D.set(w.x, w.y, 0);
  if (isStickyActive() && !grabbedParticle) {
    document.body.style.cursor = isMouseOnRope() ? 'grab' : '';
  }
});

window.addEventListener('mousedown', (e) => {
  if (!isStickyActive()) return;
  if (isMouseOnRope()) {
    grabbedParticle = getClosestParticle();
    if (grabbedParticle) {
      grabOffset.x = grabbedParticle.x - mouse3D.x;
      grabOffset.y = grabbedParticle.y - mouse3D.y;
      document.body.style.cursor = 'grabbing';
      e.preventDefault();
    }
  }
});

window.addEventListener('mouseup', () => {
  if (grabbedParticle) {
    grabbedParticle = null;
    document.body.style.cursor = isMouseOnRope() ? 'grab' : '';
  }
});

window.addEventListener('mouseleave', () => {
  mouse3D.set(-9999, 0, 0);
  mouse2D.x = -9999; mouse2D.y = -9999;
  grabbedParticle = null;
  document.body.style.cursor = '';
});

window.addEventListener('touchmove', (e) => {
  e.preventDefault();
  const t = e.touches[0];
  const w = screenToWorld(t.clientX, t.clientY);
  mouse3D.set(w.x, w.y, 0);
}, { passive: false });

window.addEventListener('touchstart', (e) => {
  const t = e.touches[0];
  const w = screenToWorld(t.clientX, t.clientY);
  mouse3D.set(w.x, w.y, 0);
  grabbedParticle = getClosestParticle();
});

window.addEventListener('touchend', () => {
  grabbedParticle = null;
  mouse3D.set(-9999, 0, 0);
});

// ---- Rope anchor — dynamically placed at ~72% from left ----
function computeRopeX() {
  const halfH = Math.tan(fov / 2) * camera.position.z;
  const halfW = halfH * (W / H);
  return ((cfg.ropePosition / 100) * 2 - 1) * halfW;
}
let ROPE_X = computeRopeX();

// ---- Particle class ----
class Particle {
  constructor(x, y, pinned) {
    this.x = x; this.y = y;
    this.oldX = x; this.oldY = y;
    this.pinned = pinned;
  }
}

const ropeTop    =  7.0;
const ropeBottom = -9.5;
const particles  = [];
for (let i = 0; i <= NUM_SEGMENTS; i++) {
  const t = i / NUM_SEGMENTS;
  const y = ropeTop - t * (ropeTop - ropeBottom);
  particles.push(new Particle(ROPE_X, y, i === 0));
}
const segLen = (ropeTop - ropeBottom) / NUM_SEGMENTS;

// ---- Helpers ----
function distPointToSegment(px, py, ax, ay, bx, by) {
  const abx = bx - ax, aby = by - ay;
  const len2 = abx * abx + aby * aby;
  if (len2 === 0) return Math.sqrt((px-ax)**2 + (py-ay)**2);
  let t = ((px-ax)*abx + (py-ay)*aby) / len2;
  t = Math.max(0, Math.min(1, t));
  const cx = ax + t*abx, cy = ay + t*aby;
  return Math.sqrt((px-cx)**2 + (py-cy)**2);
}

function worldToScreenXY(x, y) {
  const v = new THREE.Vector3(x, y, 0);
  v.project(camera);
  return { sx: (v.x + 1) / 2 * W, sy: (-v.y + 1) / 2 * H };
}

function distPointToSegment2D(px, py, ax, ay, bx, by) {
  const abx = bx-ax, aby = by-ay;
  const len2 = abx*abx + aby*aby;
  if (len2 === 0) return Math.sqrt((px-ax)**2 + (py-ay)**2);
  let t = ((px-ax)*abx + (py-ay)*aby) / len2;
  t = Math.max(0, Math.min(1, t));
  return Math.sqrt((px - (ax+t*abx))**2 + (py - (ay+t*aby))**2);
}

function isMouseOnRope() {
  const pCenter = new THREE.Vector3(0, 0, 0).project(camera);
  const pEdge   = new THREE.Vector3(TUBE_R, 0, 0).project(camera);
  const tubePixels = Math.abs(pEdge.x - pCenter.x) * W / 2;
  const threshold  = tubePixels * 1.1;
  for (let i = 0; i < NUM_SEGMENTS; i++) {
    const a = particles[i], b = particles[i+1];
    const sa = worldToScreenXY(a.x, a.y);
    const sb = worldToScreenXY(b.x, b.y);
    if (distPointToSegment2D(mouse2D.x, mouse2D.y, sa.sx, sa.sy, sb.sx, sb.sy) < threshold) return true;
  }
  return false;
}

// ---- Simulate ----
// ---- Grab state ----
let grabbedParticle = null;
let grabOffset = { x: 0, y: 0 };

function getClosestParticle() {
  let minDist = Infinity, closest = null;
  for (let i = 1; i < particles.length; i++) {
    const dx = particles[i].x - mouse3D.x;
    const dy = particles[i].y - mouse3D.y;
    const d  = dx*dx + dy*dy;
    if (d < minDist) { minDist = d; closest = particles[i]; }
  }
  return Math.sqrt(minDist) < TUBE_R * 8 ? closest : null;
}

function simulate() {
  for (const p of particles) {
    if (p.pinned) continue;
    const vx = (p.x - p.oldX) * DAMPING;
    const vy = (p.y - p.oldY) * DAMPING;
    p.oldX = p.x; p.oldY = p.y;
    p.x += vx;
    p.y += vy - GRAVITY;
  }

  for (let iter = 0; iter < ITERATIONS; iter++) {
    for (let i = 0; i < NUM_SEGMENTS; i++) {
      const a = particles[i], b = particles[i+1];
      const dx = b.x - a.x, dy = b.y - a.y;
      const dist = Math.sqrt(dx*dx + dy*dy) || 0.0001;
      const diff = (dist - segLen) / dist * 0.5;
      const ox = dx * diff, oy = dy * diff;
      if (!a.pinned) { a.x += ox; a.y += oy; }
      if (!b.pinned) { b.x -= ox; b.y -= oy; }
    }
    particles[0].x = ROPE_X; particles[0].y = ropeTop;
    // Mover partícula agarrada, clampeada al alcance máximo desde el ancla
    if (grabbedParticle) {
      const pIdx = particles.indexOf(grabbedParticle);
      const maxReach = pIdx * segLen * 0.82;
      const tx = mouse3D.x + grabOffset.x;
      const ty = mouse3D.y + grabOffset.y;
      const rdx = tx - ROPE_X;
      const rdy = ty - ropeTop;
      const rdist = Math.sqrt(rdx * rdx + rdy * rdy);
      if (rdist <= maxReach) {
        grabbedParticle.x = tx;
        grabbedParticle.y = ty;
      } else {
        const s = maxReach / rdist;
        grabbedParticle.x = ROPE_X + rdx * s;
        grabbedParticle.y = ropeTop + rdy * s;
      }
      grabbedParticle.oldX = grabbedParticle.x;
      grabbedParticle.oldY = grabbedParticle.y;
    }
  }
}

// ---- Rope texture ----
const ropeImg = new Image();
ropeImg.src = 'data:image/jpeg;base64,';
let ropeTex = new THREE.Texture(ropeImg);
ropeTex.wrapS = THREE.RepeatWrapping;
ropeTex.wrapT = THREE.RepeatWrapping;
ropeTex.repeat.set(60, 2);
ropeImg.onload = () => { ropeTex.needsUpdate = true; };

// ---- Tube geometry (Catmull-Rom smooth render curve) ----
function catmullRom(p0, p1, p2, p3, t) {
  const t2 = t * t, t3 = t2 * t;
  return {
    x: 0.5 * ((2 * p1.x) + (-p0.x + p2.x) * t + (2 * p0.x - 5 * p1.x + 4 * p2.x - p3.x) * t2 + (-p0.x + 3 * p1.x - 3 * p2.x + p3.x) * t3),
    y: 0.5 * ((2 * p1.y) + (-p0.y + p2.y) * t + (2 * p0.y - 5 * p1.y + 4 * p2.y - p3.y) * t2 + (-p0.y + 3 * p1.y - 3 * p2.y + p3.y) * t3),
  };
}

function getRenderCurve() {
  const curve = new Array(RENDER_N);
  let ri = 0;
  for (let i = 0; i < NUM_SEGMENTS; i++) {
    const p0 = particles[Math.max(0, i - 1)];
    const p1 = particles[i];
    const p2 = particles[i + 1];
    const p3 = particles[Math.min(N - 1, i + 2)];
    for (let s = 0; s < RENDER_SUBDIV; s++) {
      curve[ri++] = catmullRom(p0, p1, p2, p3, s / RENDER_SUBDIV);
    }
  }
  const tip = particles[N - 1];
  curve[ri] = { x: tip.x, y: tip.y };
  return curve;
}

function getRenderTan(curve, i) {
  let dx, dy;
  if (i === 0) {
    dx = curve[1].x - curve[0].x;
    dy = curve[1].y - curve[0].y;
  } else if (i === curve.length - 1) {
    dx = curve[i].x - curve[i - 1].x;
    dy = curve[i].y - curve[i - 1].y;
  } else {
    const im = Math.max(0, i - 2);
    const ip = Math.min(curve.length - 1, i + 2);
    dx = curve[ip].x - curve[im].x;
    dy = curve[ip].y - curve[im].y;
  }
  const l = Math.sqrt(dx * dx + dy * dy) || 0.001;
  return [dx / l, dy / l];
}

function fillTubePositions(pos, curve) {
  let pi = 0;
  for (let i = 0; i < curve.length; i++) {
    const [tx, ty] = getRenderTan(curve, i);
    const nx = -ty, ny = tx;
    for (let j = 0; j < TUBE_SEGS; j++) {
      const a = (j / TUBE_SEGS) * Math.PI * 2;
      const cx = Math.cos(a), cy = Math.sin(a);
      pos[pi++] = curve[i].x + nx * cx * TUBE_R;
      pos[pi++] = curve[i].y + ny * cx * TUBE_R;
      pos[pi++] = cy * TUBE_R;
    }
  }
}

function buildTubeArrays() {
  const curve = getRenderCurve();
  const pos = new Float32Array(RENDER_N * TUBE_SEGS * 3);
  const uv  = new Float32Array(RENDER_N * TUBE_SEGS * 2);
  const idx = [];

  let ui = 0;
  for (let i = 0; i < RENDER_N; i++) {
    for (let j = 0; j < TUBE_SEGS; j++) {
      uv[ui++] = i / (RENDER_N - 1);
      uv[ui++] = j / TUBE_SEGS;
    }
  }
  fillTubePositions(pos, curve);

  for (let i = 0; i < RENDER_N - 1; i++) {
    for (let j = 0; j < TUBE_SEGS; j++) {
      const a = i * TUBE_SEGS + j;
      const b = i * TUBE_SEGS + (j + 1) % TUBE_SEGS;
      const c = (i + 1) * TUBE_SEGS + j;
      const d = (i + 1) * TUBE_SEGS + (j + 1) % TUBE_SEGS;
      idx.push(a, c, b, b, c, d);
    }
  }
  return { pos, uv, idx };
}

const { pos: initPos, uv: initUV, idx: initIdx } = buildTubeArrays();
const tubeGeo = new THREE.BufferGeometry();
tubeGeo.setAttribute('position', new THREE.BufferAttribute(initPos, 3));
tubeGeo.setAttribute('uv',       new THREE.BufferAttribute(initUV,  2));
tubeGeo.setIndex(initIdx);
tubeGeo.computeVertexNormals();

const tubeMat = new THREE.MeshLambertMaterial({
  map:   ropeTex,
  color: 0xffffff,   // Lambert = difuso puro, sin specular, 100% mate
});
const tubeMesh = new THREE.Mesh(tubeGeo, tubeMat);
scene.add(tubeMesh);

// ---- Tip cap — esfera que cierra el extremo inferior de la soga ----
const tipGeo  = new THREE.SphereGeometry(TUBE_R, 12, 8);
const tipMesh = new THREE.Mesh(tipGeo, tubeMat);
scene.add(tipMesh);

scene.add(new THREE.AmbientLight(0xffffff, 0.9));
const dl = new THREE.DirectionalLight(0xffffff, 1.2);
dl.position.set(2, 3, 4);
scene.add(dl);
const bl = new THREE.DirectionalLight(0xaaaaaa, 0.4);
bl.position.set(-2, -1, 2);
scene.add(bl);

function updateTube() {
  const pos = tubeGeo.attributes.position.array;
  fillTubePositions(pos, getRenderCurve());
  tubeGeo.attributes.position.needsUpdate = true;
  tubeGeo.computeVertexNormals();
}

// ---- Cards (contenido editable desde Webflow) ----
// Dentro de .soga-cards-layer, agregá Div Blocks con clase "stat-card".
// Opcional: data-rope-index="15" para fijar en qué punto de la soga va cada card.
const stickyRoot = document.querySelector('.soga-sticky-wrapper');
if (stickyRoot) stickyRoot.classList.add('soga-js-active');

const cardsLayer = document.querySelector('.soga-cards-layer');

// Borrar cards creadas por versiones viejas del JS (no tienen data-rope-index)
cardsLayer?.querySelectorAll(':scope > .stat-card:not([data-rope-index])').forEach((el) => el.remove());

const cardEls = cardsLayer
  ? [...cardsLayer.querySelectorAll(':scope > .stat-card[data-rope-index]')]
  : [];

// Ocultar duplicados fuera del layer (ej. cards viejas en un Embed)
document.querySelectorAll('.soga-sticky-wrapper .stat-card[data-rope-index]').forEach((el) => {
  if (!cardEls.includes(el)) el.setAttribute('hidden', '');
});

const DEFAULT_CARD_RATIOS = [3, 15, 27, 39, 51, 63].map(i => i / 80);
const CARD_INDICES = cardEls.map((el, i) => {
  const idx = parseInt(el.dataset.ropeIndex, 10);
  if (Number.isFinite(idx)) return Math.max(1, Math.min(NUM_SEGMENTS, idx));
  const ratio = DEFAULT_CARD_RATIOS[i] ?? (i + 1) / (cardEls.length + 1);
  return Math.round(ratio * NUM_SEGMENTS);
});

function bindCardGrab(el, idx) {
  el.addEventListener('mousedown', (e) => {
    const p = particles[CARD_INDICES[idx]];
    grabbedParticle = p;
    grabOffset.x = p.x - mouse3D.x;
    grabOffset.y = p.y - mouse3D.y;
    document.body.style.cursor = 'grabbing';
    e.preventDefault();
    e.stopPropagation();
  });
  el.addEventListener('touchstart', (e) => {
    const t = e.touches[0];
    const w = screenToWorld(t.clientX, t.clientY);
    mouse3D.set(w.x, w.y, 0);
    const p = particles[CARD_INDICES[idx]];
    grabbedParticle = p;
    grabOffset.x = p.x - mouse3D.x;
    grabOffset.y = p.y - mouse3D.y;
    e.preventDefault();
  }, { passive: false });
  el.style.cursor = 'grab';
  el.style.right = 'auto';
  el.style.bottom = 'auto';
  el.style.margin = '0';
}

cardEls.forEach(bindCardGrab);

// ---- Scroll directo via getBoundingClientRect — sin depender de GSAP/Lenis ----
const CAM_START_Y  =  5.8;
const CAM_END_Y    = -7.8;
const CAM_RANGE    = CAM_START_Y - CAM_END_Y;  // 13.6
const EXTRA_SCROLL = cfg.scrollDist;

const triggerEl = document.querySelector('.soga-transformation, .section_transformation');
triggerEl.style.height = `calc(100vh + ${EXTRA_SCROLL}px)`;

// Target suave — el lerp en el animate loop lo persigue
let targetCamY = CAM_START_Y;
camera.position.y = CAM_START_Y;

function updateCameraTarget() {
  const rect = triggerEl.getBoundingClientRect();
  // rect.top = 0 → sticky empieza (progreso 0)
  // rect.top = -EXTRA_SCROLL → sticky termina (progreso 1)
  const progress = Math.max(0, Math.min(1, -rect.top / EXTRA_SCROLL));
  targetCamY = CAM_START_Y - progress * CAM_RANGE;
}

window.addEventListener('scroll', updateCameraTarget, { passive: true });
updateCameraTarget(); // estado inicial

// ---- THREE.js render loop ----
const projVec = new THREE.Vector3();
function worldToScreen(x, y) {
  projVec.set(x, y, 0);
  projVec.project(camera);
  return { sx: (projVec.x + 1) / 2 * W, sy: (-projVec.y + 1) / 2 * H };
}

let frame = 0;
function animate() {
  requestAnimationFrame(animate);
  frame++;
  simulate();
  updateTube();

  // Mover tip cap al último partícula de la soga
  const lp = particles[NUM_SEGMENTS];
  tipMesh.position.set(lp.x, lp.y, 0);

  for (let ci = 0; ci < CARD_INDICES.length; ci++) {
    const p     = particles[CARD_INDICES[ci]];
    const angle = Math.sin(frame * 0.007 + ci * 1.1) * 0.01;
    const { sx, sy } = worldToScreen(p.x, p.y);
    // Cada card sigue perfectamente su partícula de la soga (X e Y)
    const card = cardEls[ci];
    card.style.left      = sx + 'px';
    card.style.top       = sy + 'px';
    card.style.transform = `translate(-50%, -50%) rotate(${angle}rad)`;
    card.classList.add('soga-positioned');
  }

  // Lerp suave hacia el target (0.06 = inercia natural)
  camera.position.y += (targetCamY - camera.position.y) * 0.06;

  renderer.render(scene, camera);
}

animate();

// ---- Resize ----
window.addEventListener('resize', () => {
  W = window.innerWidth;
  H = window.innerHeight;
  camera.aspect = W / H;
  camera.updateProjectionMatrix();
  renderer.setSize(W, H);
  ROPE_X = computeRopeX();
  particles[0].x = ROPE_X;
  particles[0].oldX = ROPE_X;
});
